const brandingB64 = '';
// Scroll-triggered animations
const animEls = document.querySelectorAll('.schedule-section, .photo-section, .history-section, .schedule-card, .profile-section, .news-section, .results-section, .admin-section');
const observer = new IntersectionObserver((entries) => {
  entries.forEach((entry, i) => {
    if (entry.isIntersecting) {
      entry.target.style.transitionDelay = entry.target.classList.contains('schedule-card') ? `${i * 0.1}s` : '0s';
      entry.target.classList.add('anim-visible');
      observer.unobserve(entry.target);
    }
  });
}, { threshold: 0.15, rootMargin: '0px 0px -50px 0px' });

animEls.forEach((el, i) => {
  el.classList.add('anim-hidden');
  observer.observe(el);
});

const photoInput = document.getElementById('photoInput');
const photoPreview = document.getElementById('photoPreview');
const photoCircle = document.getElementById('photoCircle');
const downloadBtn = document.getElementById('downloadBtn');
let currentPhoto = null;

if (photoInput) {
  photoInput.addEventListener('change', function(e) {
    const file = e.target.files[0];
    if (!file) return;
    const reader = new FileReader();
    reader.onload = function(ev) {
      currentPhoto = ev.target.result;
      photoPreview.src = currentPhoto;
      photoCircle.classList.add('has-photo');
      downloadBtn.disabled = false;
    };
    reader.readAsDataURL(file);
  });
}

if (downloadBtn) {
  downloadBtn.addEventListener('click', function() {
  if (!currentPhoto) return;
  downloadBtn.classList.add('loading');
  downloadBtn.textContent = 'Обработка...';

  const canvas = document.createElement('canvas');
  const ctx = canvas.getContext('2d');
  canvas.width = 1080;
  canvas.height = 1080;

  const bg = new Image();
  bg.onload = function() {
    ctx.drawImage(bg, 0, 0, 1080, 1080);

    const userImg = new Image();
    userImg.onload = function() {
      ctx.save();
      ctx.beginPath();
      ctx.arc(540, 400, 200, 0, Math.PI * 2);
      ctx.closePath();
      ctx.clip();
      ctx.drawImage(userImg, 540 - userImg.width/2, 400 - userImg.height/2, userImg.width, userImg.height);
      ctx.restore();

      ctx.beginPath();
      ctx.arc(540, 400, 200, 0, Math.PI * 2);
      ctx.strokeStyle = '#FFD700';
      ctx.lineWidth = 8;
      ctx.stroke();

      ctx.textAlign = 'center';
      ctx.fillStyle = '#FFD700';
      ctx.font = 'bold 48px Arial';
      ctx.shadowColor = 'rgba(0,0,0,0.7)';
      ctx.shadowBlur = 10;
      ctx.fillText('Бежим с утками', 540, 780);
      ctx.shadowBlur = 0;
      ctx.font = '24px Arial';
      ctx.fillStyle = '#fff';
      ctx.fillText('Я — участник забега!', 540, 830);

      const link = document.createElement('a');
      link.download = 'bezhim_s_utkami.jpg';
      link.href = canvas.toDataURL('image/jpeg', 0.92);
      link.click();

      downloadBtn.classList.remove('loading');
      downloadBtn.textContent = 'Скачать фото';
    };
    userImg.src = currentPhoto;
  };
  bg.src = 'data:image/jpeg;base64,' + brandingB64;
  });
}

// === Profile / Run tracking ===
const STORAGE_KEY = 'runDuckProfile';

function loadData() {
  const raw = localStorage.getItem(STORAGE_KEY);
  return raw ? JSON.parse(raw) : null;
}

function saveData(data) {
  localStorage.setItem(STORAGE_KEY, JSON.stringify(data));
}

function renderDashboard() {
  const data = loadData();
  const regEl = document.getElementById('profileRegister');
  const dashEl = document.getElementById('profileDashboard');
  if (!data || !data.name) {
    regEl.style.display = 'block';
    dashEl.style.display = 'none';
    return;
  }
  regEl.style.display = 'none';
  dashEl.style.display = 'block';

  document.getElementById('profileGreeting').textContent = '👋 Привет, ' + data.name + '!';

  const runs = data.runs || [];
  const totalRuns = runs.length;
  const totalDist = runs.reduce((s, r) => s + (parseFloat(r.dist) || 0), 0);
  const longest = runs.reduce((m, r) => Math.max(m, parseFloat(r.dist) || 0), 0);
  const avg = totalRuns > 0 ? (totalDist / totalRuns) : 0;

  document.getElementById('statRuns').textContent = totalRuns;
  document.getElementById('statDist').textContent = totalDist.toFixed(1);
  document.getElementById('statLongest').textContent = longest.toFixed(1);
  document.getElementById('statAvg').textContent = avg.toFixed(1);

  // run list - table
  const tbody = document.querySelector('#runList tbody');
  tbody.innerHTML = '';
  if (runs.length === 0) {
    tbody.innerHTML = '<tr><td colspan="4" style="text-align:center;opacity:0.5;padding:20px">Пока нет пробежек</td></tr>';
  } else {
    [...runs].reverse().forEach(function(r) {
      const tr = document.createElement('tr');
      tr.innerHTML = '<td>' + r.date + '</td><td>' + r.dist + ' км</td><td>' + (r.route || '—') + '</td><td>' + (r.time ? r.time + ' мин' : '—') + '</td>';
      tbody.appendChild(tr);
    });
  }

  // results table (separate section)
  const resBody = document.getElementById('resultsBody');
  if (resBody) {
    resBody.innerHTML = '';
    if (runs.length === 0) {
      resBody.innerHTML = '<tr><td colspan="4" style="text-align:center;opacity:0.5;padding:30px">Пока нет результатов</td></tr>';
    } else {
      [...runs].reverse().forEach(function(r) {
        const tr = document.createElement('tr');
        tr.innerHTML = '<td>' + r.date + '</td><td>' + r.dist + ' км</td><td>' + (r.route || '—') + '</td><td>' + (r.time ? r.time + ' мин' : '—') + '</td>';
        resBody.appendChild(tr);
      });
    }
  }

  // community routes
  const routesEl = document.getElementById('communityRoutes');
  routesEl.innerHTML = '';
  const routes = data.routes || [];
  if (routes.length === 0) {
    routesEl.innerHTML = '<div class="run-item" style="opacity:0.5">Маршрутов пока нет</div>';
  } else {
    [...routes].reverse().forEach(function(r) {
      const d = document.createElement('div');
      d.className = 'community-route-item';
      d.innerHTML = '<strong>' + r.name + '</strong> — ' + r.dist + ' км<br><span style="opacity:0.65">' + r.desc + '</span>';
      routesEl.appendChild(d);
    });
  }
}

document.addEventListener('DOMContentLoaded', function() {
  // set default date
  const dateInput = document.getElementById('runDate');
  if (dateInput) dateInput.valueAsDate = new Date();

  renderDashboard();

  document.getElementById('regBtn').addEventListener('click', function() {
    const name = document.getElementById('regName').value.trim();
    if (!name) return;
    const data = loadData() || {};
    data.name = name;
    data.runs = data.runs || [];
    data.routes = data.routes || [];
    saveData(data);
    renderDashboard();
  });

  document.getElementById('logRunBtn').addEventListener('click', function() {
    const data = loadData();
    if (!data) return;
    const date = document.getElementById('runDate').value;
    const dist = document.getElementById('runDist').value;
    const route = document.getElementById('runRoute').value;
    const time = document.getElementById('runTime').value;
    if (!date || !dist) return;
    data.runs = data.runs || [];
    data.runs.push({ date: date, dist: parseFloat(dist).toFixed(1), route: route, time: time });
    saveData(data);
    document.getElementById('runDate').value = '';
    document.getElementById('runDist').value = '';
    document.getElementById('runRoute').value = '';
    document.getElementById('runTime').value = '';
    renderDashboard();
  });

  document.getElementById('shareRouteBtn').addEventListener('click', function() {
    const data = loadData();
    if (!data) return;
    const name = document.getElementById('shareRouteName').value.trim();
    const desc = document.getElementById('shareRouteDesc').value.trim();
    const dist = document.getElementById('shareRouteDist').value;
    if (!name) return;
    data.routes = data.routes || [];
    data.routes.push({ name: name, desc: desc || '—', dist: parseFloat(dist || 0).toFixed(1) });
    saveData(data);
    document.getElementById('shareRouteName').value = '';
    document.getElementById('shareRouteDesc').value = '';
    document.getElementById('shareRouteDist').value = '';
    renderDashboard();
  });

  document.getElementById('resetBtn').addEventListener('click', function() {
    if (confirm('Сбросить все данные профиля?')) {
      localStorage.removeItem(STORAGE_KEY);
      renderDashboard();
    }
  });

  // === Admin panel ===
  const ADMIN_KEY = 'runDuckAdmin';
  const ADMIN_PASS = 'admin123';

  function adminLoad() {
    const raw = localStorage.getItem(ADMIN_KEY);
    return raw ? JSON.parse(raw) : null;
  }

  function adminSave(content) {
    localStorage.setItem(ADMIN_KEY, JSON.stringify(content));
  }

  function adminApplyContent(content) {
    if (!content) return;
    const tagline = document.querySelector('.hero-tagline');
    if (tagline) tagline.textContent = content.tagline || tagline.textContent;
    const sh2 = document.querySelector('#schedule h2');
    if (sh2) sh2.textContent = content.scheduleTitle || sh2.textContent;
    const nh2 = document.querySelector('#news h2');
    if (nh2) nh2.textContent = content.newsTitle || nh2.textContent;
    const hh2 = document.querySelector('#history h2');
    if (hh2) hh2.textContent = content.historyTitle || hh2.textContent;
    const hp1 = document.querySelector('#history .history-text p:first-child');
    if (hp1) hp1.textContent = content.historyP1 || hp1.textContent;
    const hp2 = document.querySelector('#history .history-text p:last-child');
    if (hp2) hp2.textContent = content.historyP2 || hp2.textContent;
    const footer = document.querySelector('.footer');
    if (footer) footer.textContent = content.footer || footer.textContent;
  }

  function adminPopulateForm() {
    const content = adminLoad() || {};
    const getText = function(sel) { const e = document.querySelector(sel); return e ? e.textContent : ''; };
    document.getElementById('adminTagline').value = content.tagline || getText('.hero-tagline');
    document.getElementById('adminScheduleTitle').value = content.scheduleTitle || getText('#schedule h2');
    document.getElementById('adminNewsTitle').value = content.newsTitle || getText('#news h2');
    document.getElementById('adminHistoryTitle').value = content.historyTitle || getText('#history h2');
    document.getElementById('adminHistoryP1').value = content.historyP1 || getText('#history .history-text p:first-child');
    document.getElementById('adminHistoryP2').value = content.historyP2 || getText('#history .history-text p:last-child');
    document.getElementById('adminFooter').value = content.footer || getText('.footer');
  }

  // apply saved admin content on load
  const saved = adminLoad();
  if (saved) adminApplyContent(saved);

  // check if already logged in
  const adminLoginEl = document.getElementById('adminLogin');
  const adminPanelEl = document.getElementById('adminPanel');
  if (adminLoginEl && adminPanelEl && localStorage.getItem('runDuckAdminLoggedIn') === 'true') {
    adminLoginEl.style.display = 'none';
    adminPanelEl.style.display = 'block';
    adminPopulateForm();
  }

  const adminLoginBtn = document.getElementById('adminLoginBtn');
  const adminSaveBtn = document.getElementById('adminSaveBtn');
  const adminLogoutBtn = document.getElementById('adminLogoutBtn');

  if (adminLoginBtn) {
    adminLoginBtn.addEventListener('click', function() {
      const pass = document.getElementById('adminPass').value;
      if (pass === ADMIN_PASS) {
        localStorage.setItem('runDuckAdminLoggedIn', 'true');
        document.getElementById('adminLogin').style.display = 'none';
        document.getElementById('adminPanel').style.display = 'block';
        adminPopulateForm();
        document.getElementById('adminPass').value = '';
      } else {
        alert('Неверный пароль');
      }
    });
  }

  if (adminSaveBtn) {
    adminSaveBtn.addEventListener('click', function() {
      const content = {
        tagline: document.getElementById('adminTagline').value,
        scheduleTitle: document.getElementById('adminScheduleTitle').value,
        newsTitle: document.getElementById('adminNewsTitle').value,
        historyTitle: document.getElementById('adminHistoryTitle').value,
        historyP1: document.getElementById('adminHistoryP1').value,
        historyP2: document.getElementById('adminHistoryP2').value,
        footer: document.getElementById('adminFooter').value
      };
      adminSave(content);
      adminApplyContent(content);
      alert('Изменения сохранены');
    });
  }

  if (adminLogoutBtn) {
    adminLogoutBtn.addEventListener('click', function() {
      localStorage.removeItem('runDuckAdminLoggedIn');
      document.getElementById('adminLogin').style.display = 'block';
      document.getElementById('adminPanel').style.display = 'none';
    });
  }
});
